{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class AnnotationRuleReproductionTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given a type with multiple annotations inside a TypeArgumentList`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a type with multiple annotations inside a TypeArgumentList that are already split`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull
                FooDto>,
            )
            """.trimIndent()
        val formattedCode =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()

        // This test expects the code to be valid if we don't fix it, 
        // but if we fix it, we want the "bad" code to become the "good" code?
        // Actually, the issue is that the rule currently breaks the code.
        // So I'm testing that the rule DOES NOT produce violations for the compact form.
    }
}
