 19→import org.jetbrains.kotlin.psi.psiUtil.children
 20→import org.jetbrains.kotlin.psi.psiUtil.endOffset
 21→import org.jetbrains.kotlin.psi.psiUtil.leaves
 22→
 23→/**
 24→ * Ensures annotations occur immediately prior to the annotated construct
 25→ *
 26→ * https://kotlinlang.org/docs/reference/coding-conventions.html#annotation-formatting
 27→ */
 28→public class AnnotationSpacingRule : StandardRule("annotation-spacing") {
 29→    private companion object {
 30→        const val ERROR_MESSAGE = "Annotations should occur immediately before the annotated construct"
 31→    }
 32→
 33→    override fun beforeVisitChildNodes(
 34→        node: ASTNode,
 35→        autoCorrect: Boolean,
 36→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 37→    ) {
 38→        if (node.elementType != ElementType.MODIFIER_LIST && node.elementType != ElementType.FILE_ANNOTATION_LIST) {
 39→            return
 40→        }
 41→
 42→        val annotations =
 43→            node.children()
 44→                .mapNotNull { it.psi as? KtAnnotationEntry }
 45→                .toList()
 46→        if (annotations.isEmpty()) {
 47→            return
 48→        }
 49→
 50→        // Join the nodes that immediately follow the annotations (whitespace), then add the final whitespace
 51→        // if it's not a child of root. This happens when a new line separates the annotations from the annotated
 52→        // construct. In the following example, there are no whitespace children of root, but root's next sibling is the
 53→        // new line whitespace.
 54→        //
 55→        //      @JvmField
 56→        //      val s: Any
 57→        //
 58→        val whiteSpaces = (annotations.asSequence().map { it.nextSibling } + node.treeNext)
 59→            .filterIsInstance<PsiWhiteSpace>()
 60→            .take(annotations.size)
 61→            .toList()
 62→
 63→        val next = node.nextSiblingWithAtLeastOneOf(
 64→            {
 65→                !it.isWhiteSpace() &&
 66→                    it.textLength > 0 &&
 67→                    !it.isPartOf(ElementType.FILE_ANNOTATION_LIST) &&
 68→                    !it.isCommentOnSameLineAsPrevLeaf()
 69→            },
 70→            {
 71→                // Disallow multiple white spaces as well as comments
 72→                if (it.psi is PsiWhiteSpace) {
 73→                    val s = it.text
 74→                    // Ensure at least one occurrence of two line breaks
 75→                    s.indexOf("\n") != s.lastIndexOf("\n")
 76→                } else {
 77→                    it.isPartOfComment() && !it.isCommentOnSameLineAsPrevLeaf()
 78→                }
 79→            },
 80→        )
 81→        if (next != null) {
 82→            if (node.elementType != ElementType.FILE_ANNOTATION_LIST && next.isPartOfComment()) {
 83→                val psi = node.psi
 84→                emit(psi.endOffset, ERROR_MESSAGE, true)
 85→                if (autoCorrect) {
 86→                    // Special-case autocorrection when the annotation is separated from the annotated construct
 87→                    // by a comment: we need to swap the order of the comment and the annotation
 88→                    // Remove the annotation and the following whitespace
 89→                    val eolComment = node.nextSibling { it.isCommentOnSameLineAsPrevLeaf() }
 90→                    if (eolComment != null) {
 91→                        eolComment.prevSibling { it.isWhiteSpace() }?.let { it.treeParent.removeChild(it) }
 92→                        eolComment.nextSibling { it.isWhiteSpace() }?.let { it.treeParent.removeChild(it) }
 93→                        eolComment.treeParent?.removeChild(eolComment)
 94→                    } else {
 95→                        node.nextSibling { it.isWhiteSpace() }?.let { it.treeParent?.removeChild(it) }
 96→                    }
 97→                    node.treeParent.removeChild(node)
 98→
 99→                    // Insert the annotation prior to the annotated construct
100→                    val beforeAnchor = next.nextCodeSibling()
101→                    val treeParent = next.treeParent
102→                    treeParent.addChild(node, beforeAnchor)
103→                    if (eolComment != null) {
104→                        treeParent.addChild(PsiWhiteSpaceImpl(" "), beforeAnchor)
105→                        treeParent.addChild(eolComment, beforeAnchor)
106→                    }
107→                    treeParent.addChild(PsiWhiteSpaceImpl("\n"), beforeAnchor)
108→                }
109→            }
110→        }
111→        if (whiteSpaces.isNotEmpty() && node.elementType != ElementType.FILE_ANNOTATION_LIST) {
112→            // Check to make sure there are multi breaks between annotations
113→            if (whiteSpaces.any { psi -> psi.textToCharArray().count { it == '\n' } > 1 }) {
114→                val psi = node.psi
115→                emit(psi.endOffset, ERROR_MESSAGE, true)
116→                if (autoCorrect) {
117→                    removeIntraLineBreaks(node, annotations.last())
118→                    removeExtraLineBreaks(node)
119→                }
120→            }
121→        }
122→    }
123→
124→    private inline fun ASTNode.nextSiblingWithAtLeastOneOf(
125→        p: (ASTNode) -> Boolean,
126→        needsToOccur: (ASTNode) -> Boolean,
127→    ): ASTNode? {
128→        var n = this.treeNext
129→        var occurrenceCount = 0
130→        while (n != null) {
131→            if (needsToOccur(n)) {
132→                occurrenceCount++
133→            }
134→            if (p(n)) {
135→                return if (occurrenceCount > 0) {
136→                    n
137→                } else {
138→                    null
139→                }
140→            }
141→            n = n.treeNext
142→        }
143→        return null
144→    }
145→
146→    private fun removeExtraLineBreaks(node: ASTNode) {
147→        val next = node.nextSibling {
148→            it.isWhiteSpaceWithNewline()
149→        } as? LeafPsiElement
150→        if (next != null) {
151→            rawReplaceExtraLineBreaks(next)
152→        }
153→    }
154→
155→    private fun rawReplaceExtraLineBreaks(leaf: LeafPsiElement) {
156→        // Replace the extra white space with a single break
157→        val text = leaf.text
158→        val firstIndex = text.indexOf("\n") + 1
159→        val replacementText = text.substring(0, firstIndex) +
160→            text.substringAfter("\n").replace("\n", "")
161→
162→        leaf.rawReplaceWithText(replacementText)
163→    }
164→
165→    private fun removeIntraLineBreaks(
166→        node: ASTNode,
167→        last: KtAnnotationEntry,
168→    ) {
169→        val txt = node.text
170→        // Pull the next before raw replace or it will blow up
171→        val lNext = node.nextLeaf()
172→        if (node is PsiWhiteSpaceImpl) {
173→            if (txt.toCharArray().count { it == '\n' } > 1) {
174→                rawReplaceExtraLineBreaks(node)
175→            }
176→        }
177→
178→        if (lNext != null && !last.text.endsWith(lNext.text)) {
179→            removeIntraLineBreaks(lNext, last)
180→        }
181→    }
182→
183→    private fun ASTNode.isCommentOnSameLineAsPrevLeaf() =
184→        isPartOfComment() && leaves(forward = false).takeWhile { it.isWhiteSpace() }.none { "\n" in it.text }
185→}
